  1	import * as React from 'react';
  2	import { ChartBar, ChartLabel, ChartThemeColor, getCustomTheme } from '@patternfly/react-charts/victory';
  3	
  4	import { useRefWidth } from '../utils/ref-width-hook';
  5	import { DataPoint, getInstantVectorStats } from './helpers';
  6	import { GraphEmpty } from './graph-empty';
  7	import { CustomDataSource } from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-data-source';
  8	import { humanizeNumber } from '../utils/units';
  9	import { Humanize, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
 10	import { PrometheusEndpoint } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
 11	import { PrometheusGraph, PrometheusGraphLink } from './promethues-graph';
 12	
 13	const DEFAULT_BAR_WIDTH = 10;
 14	const PADDING_RATIO = 1 / 3;
 15	
 16	const barTheme = {
 17	  bar: {
 18	    style: {
 19	      labels: {
 20	        textAnchor: 'end' as const,
 21	      },
 22	    },
 23	  },
 24	  dependentAxis: {
 25	    style: {
 26	      axis: {
 27	        stroke: 'none',
 28	      },
 29	      tickLabels: {
 30	        fill: 'none',
 31	      },
 32	    },
 33	  },
 34	  independentAxis: {
 35	    style: {
 36	      axis: {
 37	        stroke: 'none',
 38	      },
 39	      tickLabels: {
 40	        textAnchor: 'start' as const,
 41	      },
 42	    },
 43	  },
 44	};
 45	
 46	const BarChart: React.FC<BarChartProps> = ({
 47	  barSpacing = 15,
 48	  barWidth = DEFAULT_BAR_WIDTH,
 49	  data = [],
 50	  LabelComponent,
 51	  loading = false,
 52	  noLink = false,
 53	  query,
 54	  theme = getCustomTheme(ChartThemeColor.blue, barTheme),
 55	  title,
 56	  titleClassName,
 57	}) => {
 58	  const [containerRef, width] = useRefWidth();
 59	
 60	  // Max space that horizontal padding should take up.
 61	  // By default, 2/3 of the horizontal space is always available for the actual bar graph.
 62	  const maxHorizontalPadding = PADDING_RATIO * width;
 63	
 64	  const padding = {
 65	    bottom: barSpacing,
 66	    left: 0,
 67	    right: Math.min(100, maxHorizontalPadding),
 68	    top: 0,
 69	  };
 70	
 71	  return (
 72	    <PrometheusGraph
 73	      ref={containerRef}
 74	      title={title}
 75	      className={titleClassName || 'graph-wrapper graph-wrapper__horizontal-bar'}
 76	    >
 77	      <PrometheusGraphLink query={noLink ? undefined : query}>
 78	        {data.length ? (
 79	          data.map((datum, index) => (
 80	            <React.Fragment key={index}>
 81	              <div className="graph-bar__label">
 82	                {LabelComponent ? (
 83	                  <LabelComponent title={datum.x} metric={datum.metric} />
 84	                ) : (
 85	                  datum.x
 86	                )}
 87	              </div>
 88	              <div className="graph-bar__chart">
 89	                <ChartBar
 90	                  barWidth={barWidth}
 91	                  data={[datum]}
 92	                  horizontal
 93	                  labelComponent={
 94	                    <ChartLabel x={width} textAnchor={theme.bar?.style?.labels?.textAnchor} />
 95	                  }
 96	                  theme={theme}
 97	                  height={barWidth + padding.bottom}
 98	                  width={width}
 99	                  domain={{ y: [0, data[0].y] }}
100	                  padding={padding}
101	                />
102	              </div>
103	            </React.Fragment>
104	          ))
105	        ) : (
106	          <GraphEmpty loading={loading} />
107	        )}
108	      </PrometheusGraphLink>
109	    </PrometheusGraph>
110	  );
111	};
112	
113	export const Bar: React.FC<BarProps> = ({
114	  barSpacing,
115	  barWidth,
116	  delay = undefined,
117	  humanize = humanizeNumber,
118	  LabelComponent,
119	  metric,
120	  namespace,
121	  noLink = false,
122	  query,
123	  theme,
124	  title,
125	  customDataSource,
126	}) => {
127	  const [response, completed] = usePrometheusPoll({
128	    delay,
129	    endpoint: PrometheusEndpoint.QUERY,
130	    namespace,
131	    query,
132	    customDataSource,
133	  });
134	  const data = getInstantVectorStats(response, metric, humanize);
135	
136	  return (
137	    <BarChart
138	      barSpacing={barSpacing}
139	      barWidth={barWidth}
140	      data={data}
141	      LabelComponent={LabelComponent}
142	      loading={!completed}
143	      noLink={noLink}
144	      query={query}
145	      theme={theme}
146	      title={title}
147	    />
148	  );
149	};
150	
151	export type LabelComponentProps = {
152	  title: Date | string | number;
153	  metric?: { [key: string]: string };
154	};
155	
156	type BarChartProps = {
157	  barSpacing?: number;
158	  barWidth?: number;
159	  data?: DataPoint[];
160	  LabelComponent?: React.ComponentType<LabelComponentProps>;
161	  loading?: boolean;
162	  noLink?: boolean;
163	  query?: string;
164	  theme?: any; // TODO figure out the best way to import VictoryThemeDefinition
165	  title?: string;
166	  titleClassName?: string;
167	};
